// Parse and validate the raw message
function parseMessage(rawContent) {
  if (!rawContent || rawContent.length > 1024 * 64) {
    throw new Error('Message content is empty or exceeds maximum size');
  }

  const contentString = rawContent.toString('utf8');
  let parsed;

  try {
    parsed = JSON.parse(contentString);
  } catch (err) {
    throw new Error('Invalid JSON in message content');
  }

  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
    throw new Error('Message must be a JSON object');
  }

  const { type, payload, correlationId, timestamp } = parsed;

  // Validate message type against allowlist
  if (typeof type !== 'string' || !ALLOWED_MESSAGE_TYPES.has(type)) {
    throw new Error(`Unknown or disallowed message type: ${sanitizeLogValue(type)}`);
  }

  // Validate correlationId if present
  if (correlationId !== undefined && !isValidUUID(correlationId)) {
    throw new Error('Invalid correlationId format');
  }

  // Validate timestamp if present
  if (timestamp !== undefined) {
    const ts = new Date(timestamp);
    if (isNaN(ts.getTime())) {
      throw new Error('Invalid timestamp');
    }
    // Reject messages older than 1 hour to prevent replay attacks
    const oneHourAgo = Date.now() - 60 * 60 * 1000;
    if (ts.getTime() < oneHourAgo) {
      throw new Error('Message timestamp is too old');
    }
  }

  // Validate payload based on message type
  const validatedPayload = validatePayload(type, payload);

  return { type, payload: validatedPayload, correlationId, timestamp };
}

// Dead letter handling
async function sendToDeadLetterQueue(channel, message, error) {
  try {
    const dlqName = `${QUEUE_NAME}.dlq`;
    await channel.assertQueue(dlqName, { durable: true });

    const headers = {
      ...message.properties.headers,
      'x-death-reason': sanitizeLogValue(error.message),
      'x-death-time': new Date().toISOString(),
      'x-original-queue': QUEUE_NAME,
    };

    channel.sendToQueue(dlqName, message.content, {
      persistent: true,
      headers,
    });
  } catch (dlqError) {
    console.error(`Failed to send to DLQ: ${sanitizeLogValue(dlqError.message)}`);
  }
}

// Main consumer
async function startConsumer() {
  if (!RABBITMQ_URL) {
    throw new Error('RABBITMQ_URL environment variable is required');
  }

  let connection;
  let channel;

  try {
    // Connect with TLS if using amqps://
    connection = await amqplib.connect(RABBITMQ_URL, {
      heartbeat: 30,
    });

    connection.on('error', (err) => {
      console.error(`RabbitMQ connection error: ${sanitizeLogValue(err.message)}`);
    });

    connection.on('close', () => {
      console.log('RabbitMQ connection closed, attempting reconnect...');
      setTimeout(startConsumer, 5000);
    });

    channel = await connection.createChannel();

    // Set prefetch to limit concurrent processing
    await channel.prefetch(10);

    // Assert queue with dead letter exchange configuration
    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-message-ttl': 86400000, // 24 hours
        'x-max-length': 100000,
      },
    });

    // Assert DLQ
    await channel.assertQueue(`${QUEUE_NAME}.dlq`, {
      durable: true,
    });

    console.log(`Consuming messages from queue: ${QUEUE_NAME}`);

    channel.consume(QUEUE_NAME, async (message) => {
      if (!message) return;

      const deliveryTag = message.fields.deliveryTag;
      let retryCount = (message.properties.headers && message.properties.headers['x-retry-count']) || 0;

      try {
        // Parse and validate the message
        const { type, payload, correlationId } = parseMessage(message.content);

        console.log(`Processing message type: ${sanitizeLogValue(type)}, correlationId: ${sanitizeLogValue(correlationId || 'none')}`);

        // Get the handler for this message type
        const handler = messageHandlers[type];
        if (!handler) {
          throw new Error(`No handler registered for message type: ${sanitizeLogValue(type)}`);
        }

        // Execute the handler
        await handler(payload);

        // Acknowledge successful processing
        channel.ack(message);
        console.log(`Message processed successfully: ${sanitizeLogValue(type)}`);

      } catch (error) {
        console.error(`Error processing message (delivery ${deliveryTag}): ${sanitizeLogValue(error.message)}`);

        const MAX_RETRIES = 3;

        if (retryCount < MAX_RETRIES) {
          // Requeue with incremented retry count
          try {
            const headers = {
              ...message.properties.headers,
              'x-retry-count': retryCount + 1,
              'x-last-error': sanitizeLogValue(error.message),
            };

            // Nack without requeue, then republish with delay
            channel.nack(message, false, false);

            // Republish with updated headers
            channel.sendToQueue(QUEUE_NAME, message.content, {
              persistent: true,
              headers,
              expiration: String(Math.pow(2, retryCount) * 1000), // Exponential backoff
            });

            console.log(`Message requeued (retry ${retryCount + 1}/${MAX_RETRIES})`);
          } catch (requeueError) {
            console.error(`Failed to requeue message: ${sanitizeLogValue(requeueError.message)}`);
            channel.nack(message, false, false);
          }
        } else {
          // Max retries exceeded, send to DLQ
          console.error(`Max retries exceeded, sending to DLQ`);
          await sendToDeadLetterQueue(channel, message, error);
          channel.nack(message, false, false);
        }
      }
    }, {
      noAck: false, // Manual acknowledgment
    });

  } catch (error) {
    console.error(`Failed to start consumer: ${sanitizeLogValue(error.message)}`);
    if (channel) {
      try { await channel.close(); } catch (e) { /* ignore */ }
    }
    if (connection) {
      try { await connection.close(); } catch (e) { /* ignore */ }
    }
    // Retry connection
    setTimeout(startConsumer, 5000);
  }
}

// Graceful shutdown
async function shutdown(signal) {
  console.log(`Received ${signal}, shutting down gracefully...`);
  try {
    await pool.end();
    console.log('Database pool closed');
  } catch (err) {
    console.error(`Error closing database pool: ${sanitizeLogValue(err.message)}`);
  }
  process.exit(0);
}

